1	/**
2	 * OpenAIAdapter — direct OpenAI API integration via the official `openai` SDK.
3	 *
4	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
5	 * - Calls OpenAI's REST API directly using the official SDK.
6	 * - NO Vercel AI SDK and NO OpenRouter in this path.
7	 * - Authenticates via `OPENAI_API_KEY` env var.
8	 *
9	 * Caching strategy (round 1 — automatic prefix caching):
10	 * - OpenAI auto-caches prompts >= 1024 tokens on the same stable prefix; no
11	 *   client action required. Cache hits show up in
12	 *   `usage.prompt_tokens_details.cached_tokens` and are normalized into
13	 *   `OracleUsage.cachedInputTokens`.
14	 * - Explicit cache-retention extensions (`prompt_cache_key`,
15	 *   `prompt_cache_retention`) are a round-2 follow-up.
16	 *
17	 * Structured output:
18	 * - Uses `response_format: { type: 'json_schema', json_schema: { name,
19	 *   strict: true, schema } }`. Strict mode enforces the JSON Schema 100%
20	 *   on the model — refusals come back as a `refusal` field on the message.
21	 *
22	 * Per docs/oracle/02-provider-native-ai-architecture.md → "OpenAI direct".
23	 */
24	
25	import OpenAI, { toFile } from 'openai';
26	import type { ChatCompletion, ChatCompletionMessageParam } from 'openai/resources/chat/completions';
27	import type {
28	  OracleObjectResult,
29	  OracleTextResult,
30	  OracleUsage,
31	} from '../client/types';
32	import type { OracleModelRoute, ReasoningEffort } from '../routes';
33	import type {
34	  BatchResultItem,
35	  BatchStatus,
36	  GenerateObjectArgs,
37	  GenerateTextArgs,
38	  OracleProviderAdapter,
39	  RetrieveBatchArgs,
40	  RetrieveBatchResult,
41	  SubmitBatchArgs,
42	  SubmitBatchResult,
43	} from './types';
44	import { pickOpenAICacheRetention } from './cache-utils';
45	import { flattenPlan, parseJsonOrRaw, tryZodParse, zodToJsonSchema } from './vertex-gemini-adapter';
46	
47	export interface OpenAIAdapterOptions {
48	  /** API key. Defaults to env OPENAI_API_KEY. */
49	  apiKey?: string;
50	  /** OpenAI organization. Defaults to env OPENAI_ORG_ID. */
51	  organization?: string;
52	}
53	
54	export class OpenAIAdapter implements OracleProviderAdapter {
55	  readonly provider = 'openai' as const;
56	  private readonly client: OpenAI;
57	
58	  constructor(opts: OpenAIAdapterOptions = {}) {
59	    const apiKey = opts.apiKey ?? process.env.OPENAI_API_KEY;
60	    if (!apiKey) {
61	      throw new Error(
62	        'OpenAIAdapter: OPENAI_API_KEY is not set. ' +
63	          'Set it in .env.local or pass {apiKey} explicitly.',
64	      );
65	    }
66	    this.client = new OpenAI({
67	      apiKey,
68	      organization: opts.organization ?? process.env.OPENAI_ORG_ID,
69	    });
70	  }
71	
72	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
73	    const { plan, route, providerOptions } = args;
74	    const { systemPrompt, userMessage } = flattenPlan(plan);
75	    const messages = this.buildMessages(systemPrompt, userMessage, providerOptions);
76	    const callStartedAt = Date.now();
77	    const reasoningEffort = openaiEffort(route.reasoningEffort);
78	    const promptCacheRetention = pickOpenAICacheRetention(plan.taskType, providerOptions);
79	    const completion = await this.client.chat.completions.create({
80	      model: route.modelId,
81	      messages,
82	      prompt_cache_retention: promptCacheRetention,
83	      temperature:
84	        typeof providerOptions?.temperature === 'number'
85	          ? providerOptions.temperature
86	          : undefined,
87	      ...(reasoningEffort ? { reasoning_effort: reasoningEffort } : {}),
88	    });
89	    const latencyMs = Date.now() - callStartedAt;
90	    const choice = completion.choices[0];
91	    return {
92	      text: choice?.message?.content ?? '',
93	      usage: this.normalizeUsage(completion, latencyMs),
94	      rawResponse: completion,
95	    };
96	  }
97	
98	  async generateObject<TSchema, TOutput>(
99	    args: GenerateObjectArgs<TSchema>,
100	  ): Promise<OracleObjectResult<TOutput>> {
101	    const { plan, route, schema, providerOptions } = args;
102	    const { systemPrompt, userMessage } = flattenPlan(plan);
103	    // OpenAI strict mode requires every property to be required +
104	    // additionalProperties: false. The Zod JSON-schema converter produces
105	    // this shape for closed objects; we layer one safety net on top.
106	    const jsonSchema = stripIncompatibleFields(
107	      zodToJsonSchema(schema) as Record<string, unknown>,
108	    );
109	    const callStartedAt = Date.now();
110	    const reasoningEffort = openaiEffort(route.reasoningEffort);
111	    const promptCacheRetention = pickOpenAICacheRetention(plan.taskType, providerOptions);
112	    const completion = await this.client.chat.completions.create({
113	      model: route.modelId,
114	      messages: this.buildMessages(systemPrompt, userMessage),
115	      prompt_cache_retention: promptCacheRetention,
116	      temperature: 0.1,
117	      response_format: {
118	        type: 'json_schema',
119	        json_schema: {
120	          name: 'oracle_structured_output',
121	          strict: true,
122	          schema: jsonSchema,
123	        },
124	      },
125	      ...(reasoningEffort ? { reasoning_effort: reasoningEffort } : {}),
126	    });
127	    const latencyMs = Date.now() - callStartedAt;
128	    const choice = completion.choices[0];
129	    const refusal = choice?.message?.refusal;
130	    if (refusal) {
131	      throw new Error(`OpenAIAdapter.generateObject: model refused: ${refusal}`);
132	    }
133	    const raw = choice?.message?.content;
134	    if (!raw) {
135	      throw new Error(
136	        `OpenAIAdapter.generateObject: empty response. finish_reason=${choice?.finish_reason}`,
137	      );
138	    }
139	    const parsed = parseJsonOrRaw(raw);
140	    const validated = tryZodParse<TOutput>(schema, parsed);
141	    return {
142	      object: (validated ?? parsed) as TOutput,
143	      usage: this.normalizeUsage(completion, latencyMs),
144	      rawResponse: completion,
145	    };
146	  }
147	
148	  /**
149	   * Submit a batch of requests to OpenAI's Batch API. Builds a JSONL file
150	   * (one request per line, each with a caller-supplied `custom_id`),
151	   * uploads it via `client.files.create`, then opens the batch via
152	   * `client.batches.create` against `/v1/chat/completions`. 50% off sync
153	   * pricing with a 24-hour SLA.
154	   *
155	   * Returns the batch ID + the input file ID (so retrieveBatch can clean it
156	   * up after results are pulled, if desired).
157	   */
158	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
159	    const { route, requests, jsonSchema } = args;
160	    const reasoningEffort = openaiEffort(route.reasoningEffort);
161	    const sharedResponseFormat = jsonSchema
162	      ? {
163	          type: 'json_schema' as const,
164	          json_schema: {
165	            name: 'oracle_structured_output',
166	            strict: true,
167	            schema: stripIncompatibleFields(jsonSchema as Record<string, unknown>),
168	          },
169	        }
170	      : undefined;
171	
172	    const lines: string[] = [];
173	    for (const req of requests) {
174	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
175	      const body: Record<string, unknown> = {
176	        model: route.modelId,
177	        messages: this.buildMessages(systemPrompt, userMessage),
178	        temperature: jsonSchema ? 0.1 : undefined,
179	      };
180	      if (sharedResponseFormat) body.response_format = sharedResponseFormat;
181	      if (reasoningEffort) body.reasoning_effort = reasoningEffort;
182	      // Strip undefined to keep the JSONL clean.
183	      for (const k of Object.keys(body)) if (body[k] === undefined) delete body[k];
184	
185	      lines.push(JSON.stringify({
186	        custom_id: req.customId,
187	        method: 'POST',
188	        url: '/v1/chat/completions',
189	        body,
190	      }));
191	    }
192	    const jsonl = lines.join('\n') + '\n';
193	
194	    const uploaded = await this.client.files.create({
195	      file: await toFile(Buffer.from(jsonl, 'utf-8'), 'oracle-batch-input.jsonl'),
196	      purpose: 'batch',
197	    });
198	
199	    const batch = await this.client.batches.create({
200	      input_file_id: uploaded.id,
201	      endpoint: '/v1/chat/completions',
202	      completion_window: '24h',
203	    });
204	
205	    return {
206	      providerBatchId: batch.id,
207	      providerMetadata: { inputFileId: uploaded.id },
208	    };
209	  }
210	
211	  /**
212	   * Poll status and, when complete, download and parse the output JSONL.
213	   * Each output line carries the caller's `custom_id` so results map back
214	   * to the originating BatchRequest.
215	   */
216	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
217	    const { providerBatchId } = args;
218	    const batch = await this.client.batches.retrieve(providerBatchId);
219	    const status = mapOpenAIBatchStatus(batch.status);
220	    const counts = batch.request_counts;
221	
222	    if (status === 'in_progress' || status === 'submitted') {
223	      return {
224	        status,
225	        requestCount: counts?.total,
226	        completedCount: counts?.completed,
227	        failedCount: counts?.failed,
228	      };
229	    }
230	
231	    if (status !== 'completed') {
232	      // failed / expired / canceled — surface the first error if available
233	      const errMsg = batch.errors?.data?.[0]?.message;
234	      return {
235	        status,
236	        error: errMsg,
237	        requestCount: counts?.total,
238	        completedCount: counts?.completed,
239	        failedCount: counts?.failed,
240	      };
241	    }
242	
243	    if (!batch.output_file_id) {
244	      return {
245	        status: 'failed',
246	        error: 'completed batch has no output_file_id',
247	      };
248	    }
249	
250	    const fileResponse = await this.client.files.content(batch.output_file_id);
251	    const outputText = await fileResponse.text();
252	    const results: BatchResultItem[] = [];
253	
254	    for (const rawLine of outputText.split('\n')) {
255	      if (!rawLine.trim()) continue;
256	      let parsed: {
257	        custom_id: string;
258	        response: { status_code: number; body: ChatCompletion } | null;
259	        error: { code?: string; message?: string } | null;
260	      };
261	      try {
262	        parsed = JSON.parse(rawLine);
263	      } catch {
264	        // Malformed line — skip. The customId is lost; downstream will see
265	        // a missing result for one of its requests and mark it failed.
266	        continue;
267	      }
268	
269	      if (parsed.error || !parsed.response) {
270	        results.push({
271	          customId: parsed.custom_id,
272	          success: false,
273	          error: parsed.error?.message ?? `status ${parsed.response?.status_code ?? 'unknown'}`,
274	        });
275	        continue;
276	      }
277	
278	      const completion = parsed.response.body;
279	      const choice = completion.choices?.[0];
280	      const refusal = choice?.message?.refusal;
281	      if (refusal) {
282	        results.push({
283	          customId: parsed.custom_id,
284	          success: false,
285	          error: `model refused: ${refusal}`,
286	          usage: this.normalizeUsage(completion, 0),
287	        });
288	        continue;
289	      }
290	
291	      const rawContent = choice?.message?.content ?? '';
292	      // Try JSON parse first (structured output); fall back to plain text.
293	      let output: unknown;
294	      let text: string | undefined;
295	      try {
296	        output = JSON.parse(rawContent);
297	      } catch {
298	        text = rawContent;
299	      }
300	
301	      results.push({
302	        customId: parsed.custom_id,
303	        success: true,
304	        output,
305	        text,
306	        usage: this.normalizeUsage(completion, 0),
307	      });
308	    }
309	
310	    return {
311	      status: 'completed',
312	      results,
313	      requestCount: counts?.total,
314	      completedCount: counts?.completed,
315	      failedCount: counts?.failed,
316	    };
317	  }
318	
319	  private buildMessages(
320	    systemPrompt: string,
321	    userMessage: string,
322	    providerOptions?: Record<string, unknown>,
323	  ): ChatCompletionMessageParam[] {
324	    const override = providerOptions?.messages as
325	      | ChatCompletionMessageParam[]
326	      | undefined;
327	    if (Array.isArray(override) && override.length > 0) {
328	      if (systemPrompt && !override.some((m) => m.role === 'system')) {
329	        return [{ role: 'system', content: systemPrompt }, ...override];
330	      }
331	      return override;
332	    }
333	    const msgs: ChatCompletionMessageParam[] = [];
334	    if (systemPrompt) msgs.push({ role: 'system', content: systemPrompt });
335	    msgs.push({ role: 'user', content: userMessage });
336	    return msgs;
337	  }
338	
339	  /**
340	   * Normalize OpenAI usage. OpenAI exposes auto-prefix-cache reads under
341	   * `usage.prompt_tokens_details.cached_tokens`, and reasoning tokens (o-series)
342	   * under `usage.completion_tokens_details.reasoning_tokens`.
343	   */
344	  private normalizeUsage(
345	    completion: ChatCompletion,
346	    latencyMs: number,
347	  ): OracleUsage {
348	    const u = completion.usage;
349	    return {
350	      inputTokens: u?.prompt_tokens,
351	      outputTokens: u?.completion_tokens,
352	      cachedInputTokens: u?.prompt_tokens_details?.cached_tokens,
353	      reasoningTokens: u?.completion_tokens_details?.reasoning_tokens,
354	      latencyMs,
355	      providerRequestId: completion.id,
356	      rawUsageJson: u,
357	    };
358	  }
359	}
360	
361	/**
362	 * OpenAI's strict JSON-schema mode rejects certain keywords that Zod's
363	 * converter emits but the OpenAPI subset doesn't support — most commonly
364	 * `$schema`, `format` on unrecognised types, and `default` on optional
365	 * properties. Strip them defensively so the schema validates server-side.
366	 */
367	function stripIncompatibleFields(
368	  schema: Record<string, unknown>,
369	): Record<string, unknown> {
370	  const cloned = JSON.parse(JSON.stringify(schema)) as Record<string, unknown>;
371	  walk(cloned);
372	  return cloned;
373	}
374	
375	/**
376	 * Translate unified ReasoningEffort to OpenAI's `reasoning_effort` enum.
377	 * Only meaningful for the o-series (o1/o3/o4) and GPT-5 reasoning models —
378	 * non-reasoning models silently accept and ignore the param.
379	 *
380	 * 'off' returns undefined so the caller can omit the param entirely.
381	 */
382	function openaiEffort(effort: ReasoningEffort | undefined): 'low' | 'medium' | 'high' | undefined {
383	  if (!effort || effort === 'off') return undefined;
384	  return effort; // 'low' | 'medium' | 'high' pass through unchanged
385	}
386	
387	function walk(node: unknown): void {
388	  if (node === null || typeof node !== 'object') return;
389	  if (Array.isArray(node)) {
390	    for (const item of node) walk(item);
391	    return;
392	  }
393	  const obj = node as Record<string, unknown>;
394	  delete obj.$schema;
395	  delete obj.default;
396	  for (const value of Object.values(obj)) walk(value);
397	}
398	
399	/**
400	 * Map OpenAI's batch.status enum onto our provider-agnostic BatchStatus.
401	 *
402	 *   validating | in_progress | finalizing → 'in_progress'
403	 *   completed                              → 'completed'
404	 *   failed                                 → 'failed'
405	 *   expired                                → 'expired'
406	 *   cancelling | cancelled                 → 'canceled'
407	 */
408	function mapOpenAIBatchStatus(s: string): BatchStatus {
409	  switch (s) {
410	    case 'completed': return 'completed';
411	    case 'failed': return 'failed';
412	    case 'expired': return 'expired';
413	    case 'cancelling':
414	    case 'cancelled':
415	      return 'canceled';
416	    case 'validating':
417	    case 'in_progress':
418	    case 'finalizing':
419	      return 'in_progress';
420	    default:
421	      // Unknown → treat as still-running so the drain task polls again
422	      return 'in_progress';
423	  }
424	}
