1	/**
2	 * QwenAdapter — direct Alibaba Qwen integration via Alibaba DashScope's
3	 * OpenAI-compatible endpoint.
4	 *
5	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
6	 * - Calls DashScope's OpenAI-compatible REST API using the official `openai` SDK.
7	 * - NO Vercel AI SDK and NO OpenRouter in this path.
8	 * - Authenticates via `DASHSCOPE_API_KEY` env var.
9	 *
10	 * Caching strategy:
11	 * - DashScope's OpenAI-compatible Chat Completions endpoint supports explicit
12	 *   prompt caching via per-content-block `cache_control` markers.
13	 * - This adapter marks the reusable prefix explicitly:
14	 *   - for multi-turn chat, the prefix ends at the penultimate message so the
15	 *     latest user turn stays dynamic
16	 *   - for one-shot calls, the stable system prompt is marked cacheable
17	 * - For text calls, the adapter can switch to the Responses API session-cache
18	 *   path when the caller supplies a stable `sessionCacheKey`. The chat route
19	 *   persists `previous_response_id` in Postgres so the cache survives across
20	 *   requests and processes.
21	 *
22	 * Structured output:
23	 * - Qwen supports OpenAI-compatible `response_format: { type: 'json_object' }`.
24	 *   Strict json_schema mode is not universally supported, so generateObject
25	 *   falls back to json_object + Zod validation (same pattern as DeepSeek).
26	 *
27	 * Reasoning models:
28	 * - QwQ / Qwen-3 thinking models stream reasoning tokens but don't yet expose
29	 *   a separate reasoning_content field on the OpenAI-compat endpoint. We
30	 *   capture only standard input/output tokens.
31	 */
32	
33	import OpenAI from 'openai';
34	import type { ChatCompletion, ChatCompletionMessageParam } from 'openai/resources/chat/completions';
35	import type {
36	  EasyInputMessage,
37	  Response as OpenAIResponse,
38	  ResponseUsage,
39	} from 'openai/resources/responses/responses';
40	import type {
41	  OracleObjectResult,
42	  OracleTextResult,
43	  OracleUsage,
44	} from '../client/types';
45	import type { ReasoningEffort } from '../routes';
46	import type {
47	  GenerateObjectArgs,
48	  GenerateTextArgs,
49	  OracleProviderAdapter,
50	} from './types';
51	import {
52	  getCacheHints,
53	  markLastTextPartCacheable,
54	  normalizeMessageContentArray,
55	  pickAnthropicCacheTtl,
56	  pickOpenAICacheRetention,
57	  shouldDisableCache,
58	} from './cache-utils';
59	import { flattenPlan, parseJsonOrRaw, tryZodParse } from './vertex-gemini-adapter';
60	
61	const DASHSCOPE_BASE_URL = 'https://dashscope-us.aliyuncs.com/compatible-mode/v1';
62	
63	export interface QwenAdapterOptions {
64	  /** API key. Defaults to env DASHSCOPE_API_KEY. */
65	  apiKey?: string;
66	  /** Override base URL — e.g. swap to the China-region endpoint
67	   *  `https://dashscope.aliyuncs.com/compatible-mode/v1`. */
68	  baseURL?: string;
69	}
70	
71	interface QwenUsageRaw {
72	  prompt_tokens?: number;
73	  completion_tokens?: number;
74	  prompt_tokens_details?: {
75	    cached_tokens?: number;
76	    cache_creation_input_tokens?: number;
77	  };
78	}
79	
80	export class QwenAdapter implements OracleProviderAdapter {
81	  readonly provider = 'qwen' as const;
82	  private readonly client: OpenAI;
83	
84	  constructor(opts: QwenAdapterOptions = {}) {
85	    const apiKey = opts.apiKey ?? process.env.DASHSCOPE_API_KEY;
86	    if (!apiKey) {
87	      throw new Error(
88	        'QwenAdapter: DASHSCOPE_API_KEY is not set. ' +
89	          'Set it in .env.local or pass {apiKey} explicitly.',
90	      );
91	    }
92	    this.client = new OpenAI({
93	      apiKey,
94	      baseURL: opts.baseURL ?? DASHSCOPE_BASE_URL,
95	    });
96	  }
97	
98	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
99	    const { plan, route, providerOptions } = args;
100	    const { systemPrompt, userMessage } = flattenPlan(plan);
101	    const hints = getCacheHints(providerOptions);
102	    if (hints?.sessionCacheKey || hints?.previousResponseId) {
103	      return this.generateTextViaResponsesApi(
104	        plan.taskType,
105	        route,
106	        systemPrompt,
107	        userMessage,
108	        providerOptions,
109	      );
110	    }
111	    const messages = this.buildMessages(plan.taskType, systemPrompt, userMessage, providerOptions);
112	    const callStartedAt = Date.now();
113	    const completion = await this.client.chat.completions.create({
114	      model: route.modelId,
115	      messages,
116	      temperature:
117	        typeof providerOptions?.temperature === 'number'
118	          ? providerOptions.temperature
119	          : undefined,
120	      // Qwen-specific reasoning controls pass through via `extra_body`.
121	      // DashScope's OpenAI-compat layer forwards unknown root-level params.
122	      ...qwenThinkingExtras(route.reasoningEffort),
123	    });
124	    const latencyMs = Date.now() - callStartedAt;
125	    const choice = completion.choices[0];
126	    return {
127	      text: choice?.message?.content ?? '',
128	      usage: this.normalizeUsage(completion, latencyMs),
129	      rawResponse: completion,
130	    };
131	  }
132	
133	  private async generateTextViaResponsesApi(
134	    taskType: GenerateTextArgs['plan']['taskType'],
135	    route: GenerateTextArgs['route'],
136	    systemPrompt: string,
137	    userMessage: string,
138	    providerOptions?: Record<string, unknown>,
139	  ): Promise<OracleTextResult> {
140	    const hints = getCacheHints(providerOptions);
141	    const callStartedAt = Date.now();
142	    const response = await this.client.responses.create(
143	      {
144	        model: route.modelId,
145	        instructions: systemPrompt || undefined,
146	        input: this.buildResponseInput(userMessage, providerOptions),
147	        temperature:
148	          typeof providerOptions?.temperature === 'number'
149	            ? providerOptions.temperature
150	            : undefined,
151	        prompt_cache_key: hints?.sessionCacheKey,
152	        previous_response_id: hints?.previousResponseId,
153	        prompt_cache_retention: pickOpenAICacheRetention(taskType, providerOptions),
154	        ...qwenThinkingExtras(route.reasoningEffort),
155	      },
156	      {
157	        headers: {
158	          'x-dashscope-session-cache': 'enable',
159	        },
160	      },
161	    );
162	    const latencyMs = Date.now() - callStartedAt;
163	    return {
164	      text: response.output_text ?? '',
165	      usage: this.normalizeResponseUsage(response, latencyMs),
166	      rawResponse: response,
167	    };
168	  }
169	
170	  async generateObject<TSchema, TOutput>(
171	    args: GenerateObjectArgs<TSchema>,
172	  ): Promise<OracleObjectResult<TOutput>> {
173	    const { plan, route, schema, providerOptions } = args;
174	    const { systemPrompt, userMessage } = flattenPlan(plan);
175	    const callStartedAt = Date.now();
176	    const completion = await this.client.chat.completions.create({
177	      model: route.modelId,
178	      messages: this.buildMessages(plan.taskType, systemPrompt, userMessage, providerOptions),
179	      temperature: 0.1,
180	      response_format: { type: 'json_object' },
181	      ...qwenThinkingExtras(route.reasoningEffort),
182	    });
183	    const latencyMs = Date.now() - callStartedAt;
184	    const choice = completion.choices[0];
185	    const raw = choice?.message?.content;
186	    if (!raw) {
187	      throw new Error(
188	        `QwenAdapter.generateObject: empty response. finish_reason=${choice?.finish_reason}`,
189	      );
190	    }
191	    const parsed = parseJsonOrRaw(raw);
192	    const validated = tryZodParse<TOutput>(schema, parsed);
193	    return {
194	      object: (validated ?? parsed) as TOutput,
195	      usage: this.normalizeUsage(completion, latencyMs),
196	      rawResponse: completion,
197	    };
198	  }
199	
200	  private buildMessages(
201	    taskType: GenerateTextArgs['plan']['taskType'],
202	    systemPrompt: string,
203	    userMessage: string,
204	    providerOptions?: Record<string, unknown>,
205	  ): ChatCompletionMessageParam[] {
206	    const override = providerOptions?.messages as
207	      | Array<{ role: string; content: unknown }>
208	      | undefined;
209	    if (Array.isArray(override) && override.length > 0) {
210	      const normalized = override.map((m) => ({
211	        role: m.role,
212	        content: m.content,
213	      })) as unknown as ChatCompletionMessageParam[];
214	      if (systemPrompt && !normalized.some((m) => m.role === 'system')) {
215	        normalized.unshift({ role: 'system', content: systemPrompt });
216	      }
217	      return this.applyExplicitCacheMarkers(taskType, normalized, providerOptions);
218	    }
219	    const msgs: ChatCompletionMessageParam[] = [];
220	    if (systemPrompt) msgs.push({ role: 'system', content: systemPrompt });
221	    msgs.push({ role: 'user', content: userMessage });
222	    return this.applyExplicitCacheMarkers(taskType, msgs, providerOptions);
223	  }
224	
225	  private normalizeUsage(
226	    completion: ChatCompletion,
227	    latencyMs: number,
228	  ): OracleUsage {
229	    const u = completion.usage as QwenUsageRaw | undefined;
230	    return {
231	      inputTokens: u?.prompt_tokens,
232	      outputTokens: u?.completion_tokens,
233	      cachedInputTokens: u?.prompt_tokens_details?.cached_tokens,
234	      cacheWriteTokens: u?.prompt_tokens_details?.cache_creation_input_tokens,
235	      latencyMs,
236	      providerRequestId: completion.id,
237	      rawUsageJson: u,
238	    };
239	  }
240	
241	  private normalizeResponseUsage(
242	    response: OpenAIResponse,
243	    latencyMs: number,
244	  ): OracleUsage {
245	    const u = response.usage as ResponseUsage | undefined;
246	    return {
247	      inputTokens: u?.input_tokens,
248	      outputTokens: u?.output_tokens,
249	      cachedInputTokens: u?.input_tokens_details?.cached_tokens,
250	      reasoningTokens: u?.output_tokens_details?.reasoning_tokens,
251	      latencyMs,
252	      providerRequestId: response.id,
253	      rawUsageJson: u,
254	    };
255	  }
256	
257	  private applyExplicitCacheMarkers(
258	    taskType: GenerateTextArgs['plan']['taskType'],
259	    messages: ChatCompletionMessageParam[],
260	    providerOptions?: Record<string, unknown>,
261	  ): ChatCompletionMessageParam[] {
262	    if (shouldDisableCache(providerOptions)) return messages;
263	    const ttl = pickAnthropicCacheTtl(taskType, providerOptions);
264	    const next = messages.map((message) => ({ ...message }));
265	
266	    if (next.length > 1) {
267	      const target = next[next.length - 2] as ChatCompletionMessageParam & { content?: unknown };
268	      target.content = markLastTextPartCacheable(
269	        normalizeMessageContentArray(target.content),
270	        ttl,
271	      ) as unknown as ChatCompletionMessageParam['content'];
272	      return next;
273	    }
274	
275	    const system = next.find((message) => message.role === 'system') as
276	      | (ChatCompletionMessageParam & { content?: unknown })
277	      | undefined;
278	    if (system) {
279	      system.content = markLastTextPartCacheable(
280	        normalizeMessageContentArray(system.content),
281	        ttl,
282	      ) as unknown as ChatCompletionMessageParam['content'];
283	    }
284	    return next;
285	  }
286	
287	  private buildResponseInput(
288	    userMessage: string,
289	    providerOptions?: Record<string, unknown>,
290	  ): EasyInputMessage[] {
291	    const override = providerOptions?.messages as
292	      | Array<{ role: string; content: unknown }>
293	      | undefined;
294	    const messages = Array.isArray(override) && override.length > 0
295	      ? override
296	      : [{ role: 'user', content: userMessage }];
297	
298	    return messages
299	      .filter((message) =>
300	        message.role === 'user' ||
301	        message.role === 'assistant' ||
302	        message.role === 'system',
303	      )
304	      .map((message) => ({
305	        role: message.role as EasyInputMessage['role'],
306	        content: this.stringifyResponseContent(message.content),
307	        type: 'message',
308	      }));
309	  }
310	
311	  private stringifyResponseContent(content: unknown): string {
312	    if (typeof content === 'string') return content;
313	    return normalizeMessageContentArray(content)
314	      .map((part) => String(part.text ?? ''))
315	      .filter(Boolean)
316	      .join('\n');
317	  }
318	}
