320	/**
321	 * Translate unified ReasoningEffort to Qwen / QwQ thinking parameters.
322	 *
323	 * Qwen3 thinking models accept `enable_thinking: true` (with optional
324	 * `thinking_budget` in tokens). DashScope's OpenAI-compat layer forwards
325	 * unknown top-level params verbatim, so we set them directly. Non-thinking
326	 * Qwen models silently ignore both fields.
327	 *
328	 *   off    → enable_thinking: false (forces fast path on QwQ / Qwen3-thinking)
329	 *   low    → enable_thinking: true, thinking_budget: 2048
330	 *   medium → enable_thinking: true, thinking_budget: 8192
331	 *   high   → enable_thinking: true, thinking_budget: 24576
332	 */
333	function qwenThinkingExtras(
334	  effort: ReasoningEffort | undefined,
335	): Record<string, unknown> {
336	  if (!effort) return {};
337	  if (effort === 'off') return { enable_thinking: false };
338	  const budget = effort === 'low' ? 2048 : effort === 'medium' ? 8192 : 24576;
339	  return { enable_thinking: true, thinking_budget: budget };
340	}
